// Test: can we write a minimal valid PNG using pure Node.js (zlib is built-in)?
const zlib = require('zlib');
const fs = require('fs');

// Create a minimal 1x1 test PNG
function createMinimalPNG(width, height, r, g, b) {
  // PNG signature
  const sig = Buffer.from([0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A]);

  // IHDR chunk
  const ihdrData = Buffer.allocUnsafe(13);
  ihdrData.writeUInt32BE(width, 0);
  ihdrData.writeUInt32BE(height, 4);
  ihdrData[8] = 8;   // bit depth
  ihdrData[9] = 2;   // color type: RGB
  ihdrData[10] = 0;  // compression
  ihdrData[11] = 0;  // filter
  ihdrData[12] = 0;  // interlace

  // Build raw image data
  const rowSize = width * 3;
  const raw = Buffer.allocUnsafe(height * (rowSize + 1));
  for (let y = 0; y < height; y++) {
    raw[y * (rowSize + 1)] = 0; // filter type None
    for (let x = 0; x < width; x++) {
      const idx = y * (rowSize + 1) + 1 + x * 3;
      raw[idx] = r;
      raw[idx+1] = g;
      raw[idx+2] = b;
    }
  }
  const idat = zlib.deflateSync(raw, {level: 9});

  function chunk(type, data) {
    const len = Buffer.allocUnsafe(4);
    len.writeUInt32BE(data.length, 0);
    const typeB = Buffer.from(type, 'ascii');
    const crc = require('crypto').createHash('crc32') || null;
    // Compute CRC32 manually
    const crcBuf = Buffer.concat([typeB, data]);
    let c = 0xFFFFFFFF;
    for (let i = 0; i < crcBuf.length; i++) {
      c ^= crcBuf[i];
      for (let j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
    }
    c = (c ^ 0xFFFFFFFF) >>> 0;
    const crcOut = Buffer.allocUnsafe(4);
    crcOut.writeUInt32BE(c, 0);
    return Buffer.concat([len, typeB, data, crcOut]);
  }

  const iend = chunk('IEND', Buffer.alloc(0));
  const ihdr = chunk('IHDR', ihdrData);
  const idatChunk = chunk('IDAT', idat);

  return Buffer.concat([sig, ihdr, idatChunk, iend]);
}

