import { chromium } from '@playwright/test';

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ colorScheme: 'dark' });
  const page = await context.newPage();
  await page.goto('http://localhost:3000/login', { waitUntil: 'networkidle', timeout: 30000 });

  // Check immediately (before any wait)
  const immediate = await page.evaluate(() => {
    const body = document.body;
    const bodyKeys = Object.keys(body).filter(k => k.startsWith('__'));
    // React 18 hydrates to document body in App Router
    const reactRootKey = Object.keys(document).filter(k => k.startsWith('__react'));
    // Check window-level React properties
    const windowKeys = Object.keys(window).filter(k => k.includes('react') || k.includes('React'));
    return { bodyKeys, reactRootKey, windowReactKeys: windowKeys.slice(0, 10) };
  });
  console.log('IMMEDIATE:', JSON.stringify(immediate, null, 2));

  await page.waitForTimeout(3000);

  const after = await page.evaluate(() => {
    const body = document.body;
    const bodyKeys = Object.keys(body).filter(k => k.startsWith('__'));
    // Next.js App Router: check for __next_f (RSC flight data)
    const win = window as any;
    return {
      bodyKeys,
      hasNextF: Array.isArray(win.__next_f),
      nextFLength: Array.isArray(win.__next_f) ? win.__next_f.length : 0,
      hasNextData: !!win.__NEXT_DATA__,
      // Check if React has delegated to document/body
      documentListeners: typeof (document as any).__reactFiber !== 'undefined',
    };
  });
  console.log('AFTER 3s:', JSON.stringify(after, null, 2));

  await browser.close();
}

main().catch(e => { console.error(e.message); process.exit(1); });
