import { chromium } from '@playwright/test';

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ colorScheme: 'dark' });
  const page = await context.newPage();

  await page.goto('http://localhost:3000/login', { waitUntil: 'networkidle', timeout: 30_000 });

  // Check the initial state
  const initialState = await page.evaluate(() => {
    const win = window as any;
    const nextKeys = Object.keys(win).filter(k => k.toLowerCase().includes('next'));
    const allNextVals: Record<string, string> = {};
    for (const k of nextKeys) {
      try {
        const val = win[k];
        allNextVals[k] = typeof val === 'object' ? JSON.stringify(val).slice(0, 100) : String(val).slice(0, 100);
      } catch {}
    }
    return { nextKeys, allNextVals };
  });
  console.log('Window NEXT keys at networkidle:', JSON.stringify(initialState, null, 2));

  // Wait 5 seconds and check again
  await page.waitForTimeout(5000);
  const laterState = await page.evaluate(() => {
    const win = window as any;
    const nextKeys = Object.keys(win).filter(k => k.toLowerCase().includes('next') || k.startsWith('__NEXT'));
    const allNextVals: Record<string, string> = {};
    for (const k of nextKeys) {
      try {
        const val = win[k];
        allNextVals[k] = typeof val === 'object' ? JSON.stringify(val).slice(0, 200) : String(val).slice(0, 200);
      } catch {}
    }
    // Also check for React signals  
    const reactKeys = Object.keys(win).filter(k => k.toLowerCase().includes('react'));
    // Check body keys
    const bodyKeys = Object.keys(document.body).filter(k => k.startsWith('__react'));

    return { nextKeys, allNextVals, reactKeys, bodyKeys };
  });
  console.log('Window state after 5s:', JSON.stringify(laterState, null, 2));

  // Also check if form onsubmit is set
  const formState = await page.evaluate(() => {
    const form = document.querySelector('form') as HTMLFormElement | null;
    if (!form) return { found: false };
    return {
      found: true,
      onsubmit: typeof form.onsubmit,
      formKeys: Object.keys(form).filter(k => k.startsWith('__')),
      submitBtnKeys: Object.keys(document.querySelector('button[type="submit"]') ?? {}).filter(k => k.startsWith('__')),
    };
  });
  console.log('Form state after 5s:', JSON.stringify(formState, null, 2));

  await browser.close();
}

main().catch(console.error);
