import { chromium } from '@playwright/test';

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ colorScheme: 'dark' });
  const page = await context.newPage();

  // Track all console messages and errors
  const logs: string[] = [];
  page.on('console', msg => logs.push(`[${msg.type()}] ${msg.text()}`));
  page.on('pageerror', err => logs.push(`[PAGEERROR] ${err.message}`));

  // Track resource loading
  const resources: string[] = [];
  page.on('response', resp => {
    const url = resp.url();
    if (url.includes('/_next/static/chunks') || url.includes('app-page')) {
      resources.push(`${resp.status()} ${url.replace('http://localhost:3000', '')}`);
    }
  });

  console.log('Loading login page...');
  await page.goto('http://localhost:3000/login', { waitUntil: 'load', timeout: 30_000 });

  // Wait for more resources
  await page.waitForTimeout(8000);

  console.log('\n=== CONSOLE LOGS ===');
  logs.forEach(l => console.log(l));

  console.log('\n=== RESOURCES LOADED ===');
  resources.forEach(r => console.log(r));

  // Check if ANY JS has run by seeing if window objects appeared
  const winCheck = await page.evaluate(() => {
    const win = window as any;
    return {
      allWinKeys: Object.keys(win).slice(0, 30),
      hasNextF: '__next_f' in win,
      nextFLen: win.__next_f?.length,
      hasDocument: typeof document !== 'undefined',
      // try to detect if client-side react ran
      bodyClassName: document.body.className,
      htmlDataAttr: document.documentElement.getAttribute('data-reactroot'),
    };
  });
  console.log('\n=== WINDOW CHECK ===', JSON.stringify(winCheck, null, 2));

  await browser.close();
}

main().catch(console.error);
