import { chromium } from '@playwright/test';

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ colorScheme: 'dark' });
  const page = await context.newPage();

  console.log('Loading login page...');
  await page.goto('http://localhost:3000/login', { waitUntil: 'networkidle', timeout: 60_000 });

  // Poll for hydration signals every 500ms
  for (let i = 0; i < 20; i++) {
    await page.waitForTimeout(500);
    const state = await page.evaluate(() => {
      const win = window as any;
      const keys = Object.keys(win).filter(k => k.startsWith('__'));
      return {
        NEXT_ROUTER_STATE_TREE: win.__NEXT_ROUTER_STATE_TREE,
        NEXT_ROUTER_STATE_TREE_type: typeof win.__NEXT_ROUTER_STATE_TREE,
        allDundersKeys: keys,
        formOnSubmit: typeof (document.querySelector('form') as any)?.onsubmit,
        emailInput_type: (document.querySelector('#email') as HTMLInputElement)?.type,
        emailInput_disabled: (document.querySelector('#email') as HTMLInputElement)?.disabled,
      };
    });
    console.log(`t=${((i+1)*500)}ms:`, JSON.stringify({
      router: state.NEXT_ROUTER_STATE_TREE_type,
      dunders: state.allDundersKeys,
      formOnSubmit: state.formOnSubmit,
      emailDisabled: state.emailInput_disabled,
    }));
    if (state.NEXT_ROUTER_STATE_TREE !== undefined && state.NEXT_ROUTER_STATE_TREE !== null) {
      console.log('HYDRATED at t=' + ((i+1)*500) + 'ms');
      break;
    }
  }

  await browser.close();
}

main().catch(console.error);
