import { chromium } from '@playwright/test';

const EMAIL = process.env.AUTH_EMAIL ?? 'demo@ledgerium.ai';
const PASSWORD = process.env.AUTH_PASSWORD ?? '';

async function main() {
  console.log(`Testing login as ${EMAIL}...`);
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ colorScheme: 'dark' });
  const page = await context.newPage();

  // Track URL changes
  page.on('framenavigated', frame => {
    if (frame === page.mainFrame()) {
      console.log('Navigated to:', frame.url());
    }
  });

  await page.goto('http://localhost:3000/login', { waitUntil: 'networkidle', timeout: 30_000 });
  console.log('Login page loaded:', page.url());

  // Wait for email input to be visible (sufficient hydration signal)
  const emailInput = page.locator('#email');
  await emailInput.waitFor({ state: 'visible', timeout: 10_000 });
  console.log('Email input visible');

  // Small settle for React hydration to complete
  await page.waitForTimeout(500);

  const preClickState = await page.evaluate(() => ({
    formOnSubmit: (document.querySelector('form') as any)?.onsubmit,
    emailDisabled: (document.querySelector('#email') as HTMLInputElement)?.disabled,
  }));
  console.log('Pre-click state:', JSON.stringify(preClickState));

  await emailInput.fill(EMAIL);
  const passwordInput = page.locator('#password');
  await passwordInput.fill(PASSWORD);
  console.log('Credentials filled');

  // Click submit and observe what happens
  const submitButton = page.locator('button[type="submit"]');
  await submitButton.click();
  console.log('Submit clicked, waiting 10s...');

  await page.waitForTimeout(10000);

  console.log('Final URL:', page.url());
  const bodyText = await page.evaluate(() => document.body.innerText.slice(0, 500));
  console.log('Body text:', bodyText);

  await browser.close();
}

main().catch(console.error);
